```csharp
int[] tall = { 1, 2, 3, 4, 5, 6 };

// Spørringssyntaks
var partall = from n in tall
              where n % 2 == 0
              select n;

// Metodesyntaks (samme resultat)
var ogsåPartall = tall.Where(n => n % 2 == 0);

foreach (var n in partall)
    Console.Write(n + " "); // 2 4 6
```

```csharp
// Steg 1: kilde
int[] tall = { 1, 2, 3, 4, 5 };

// Steg 2: definer spørringen (kjøres IKKE ennå)
var spørring = from n in tall
                where n > 2
                select n;

// Steg 3: utfør spørringen
foreach (var n in spørring) // nå kjøres den
    Console.Write(n + " "); // 3 4 5
```

```csharp
var studenter = new List<string> { "Ada", "Bjarne", "Anna", "Carlos" };

// Finn alle navn som starter med "A"
var aStudenter = from navn in studenter
                  where navn.StartsWith("A")
                  select navn;

foreach (var s in aStudenter)
    Console.WriteLine(s); // Ada, Anna
```

```csharp
var navn = new List<string> { "Carlos", "Ada", "Bjarne" };

// Stigende
var alfabetisk = from n in navn orderby n select n;
// Ada, Bjarne, Carlos

// Synkende
var baklengs = from n in navn orderby n descending select n;
// Carlos, Bjarne, Ada
```

```csharp
var studenter = new[]
{
    new { Navn = "Ada",    Kull = "2023" },
    new { Navn = "Bjarne", Kull = "2024" },
    new { Navn = "Anna",   Kull = "2023" }
};

var grupper = from s in studenter
               group s by s.Kull;

foreach (var g in grupper)
{
    Console.WriteLine($"Kull {g.Key}:");
    foreach (var s in g)
        Console.WriteLine($"  {s.Navn}");
}
```

